function App() {
  const [tasks, setTasks] = React.useState([
    { id: 1, title: 'Review quarterly report', priority: 'high', due: 'Today', completed: false, focusTime: 0, tags: ['work'] },
    { id: 2, title: 'Prepare presentation slides', priority: 'high', due: 'Today', completed: false, focusTime: 1800, tags: ['work'] },
    { id: 3, title: 'Read design patterns book', priority: 'medium', due: 'Tomorrow', completed: true, focusTime: 3600, tags: ['learning'] },
    { id: 4, title: 'Write unit tests', priority: 'low', due: 'Mar 30', completed: false, focusTime: 900, tags: ['coding'] },
    { id: 5, title: 'Team standup notes', priority: 'medium', due: 'Today', completed: true, focusTime: 600, tags: ['work'] },
  ]);
  const [search, setSearch] = React.useState('');
  const [filter, setFilter] = React.useState('all');

  const toggle = (id) => setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));

  const filtered = tasks.filter(t =>
    (search === '' || t.title.toLowerCase().includes(search.toLowerCase())) &&
    (filter === 'all' || (filter === 'active' ? !t.completed : t.completed))
  );

  const stats = {
    completed: tasks.filter(t => t.completed).length,
    total: tasks.length,
    focusMin: Math.round(tasks.reduce((s, t) => s + t.focusTime, 0) / 60),
    streak: 5,
  };

  const priorityClass = { high: 'bg-red-50 text-red-500', medium: 'bg-orange-50 text-orange-500', low: 'bg-emerald-50 text-emerald-500' };
  const fmt = (s) => s >= 3600 ? `${Math.floor(s/3600)}h ${Math.floor((s%3600)/60)}m` : `${Math.floor(s/60)}m`;

  return (
    <div className="min-h-screen bg-slate-50 max-w-[390px] mx-auto font-sans">
      {/* Header */}
      <div className="bg-white px-5 pt-5 pb-[14px] border-b border-slate-100">
        <div className="text-[13px] text-slate-400 mb-0.5">Monday, March 24</div>
        <div className="text-2xl font-extrabold text-slate-900 mb-4">Good morning! 👋</div>
        {/* Stats row */}
        <div className="grid grid-cols-3 gap-[10px] mb-4">
          {[
            { label: 'Completed', value: `${stats.completed}/${stats.total}`, emoji: '✅' },
            { label: 'Focus Time', value: `${stats.focusMin}m`, emoji: '⏱️' },
            { label: 'Streak', value: `${stats.streak} days`, emoji: '🔥' },
          ].map(s => (
            <div key={s.label} className="bg-slate-50 rounded-[14px] px-[10px] py-3 text-center">
              <div className="text-xl">{s.emoji}</div>
              <div className="text-[15px] font-extrabold text-slate-900 mt-1">{s.value}</div>
              <div className="text-[10px] text-slate-400">{s.label}</div>
            </div>
          ))}
        </div>
        {/* Search */}
        <div className="flex items-center bg-slate-100 rounded-xl px-[14px] py-[10px] gap-2">
          <span className="text-base">🔍</span>
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search tasks..." className="border-none bg-transparent outline-none text-sm flex-1 text-gray-700" />
        </div>
      </div>

      {/* Filter tabs */}
      <div className="flex gap-2 px-4 pt-[14px] pb-[10px] bg-white border-b border-slate-100">
        {[['all', 'All'], ['active', 'Active'], ['done', 'Done']].map(([key, label]) => (
          <button key={key} onClick={() => setFilter(key)}
            className={`px-4 py-1.5 rounded-full border-none cursor-pointer text-[13px] font-semibold transition-all duration-150 ${filter === key ? 'bg-indigo-500 text-white' : 'bg-slate-100 text-slate-500'}`}>
            {label}
          </button>
        ))}
      </div>

      {/* Task List */}
      <div className="px-4 pt-3 pb-8">
        {filtered.map(task => (
          <div key={task.id} className={`bg-white rounded-2xl px-4 py-[14px] mb-[10px] shadow-[0_1px_3px_rgba(0,0,0,0.05)] flex items-start gap-[14px] transition-opacity ${task.completed ? 'opacity-60' : 'opacity-100'}`}>
            <button onClick={() => toggle(task.id)}
              className={`w-6 h-6 rounded-full border-2 flex items-center justify-center shrink-0 mt-0.5 text-[13px] transition-all duration-150 cursor-pointer ${task.completed ? 'border-indigo-500 bg-indigo-500 text-white' : 'border-slate-200 bg-white text-white'}`}>
              {task.completed ? '✓' : ''}
            </button>
            <div className="flex-1 min-w-0">
              <div className={`text-sm font-semibold text-slate-900 mb-1 ${task.completed ? 'line-through' : ''}`}>{task.title}</div>
              <div className="flex items-center gap-2">
                <span className={`text-[11px] font-semibold px-2 py-0.5 rounded-full ${priorityClass[task.priority]}`}>{task.priority}</span>
                <span className="text-[11px] text-slate-400">📅 {task.due}</span>
                {task.focusTime > 0 && <span className="text-[11px] text-indigo-500">⏱ {fmt(task.focusTime)}</span>}
              </div>
            </div>
            <button className="bg-transparent border-none text-lg cursor-pointer text-indigo-500 shrink-0">▶</button>
          </div>
        ))}
        {filtered.length === 0 && (
          <div className="text-center py-12 text-slate-400">
            <div className="text-[40px]">🎯</div>
            <div className="text-[15px] font-semibold mt-3">No tasks found</div>
          </div>
        )}
      </div>
    </div>
  );
}

function App() {
  const [running, setRunning] = React.useState(false);
  const [seconds, setSeconds] = React.useState(25 * 60);
  const [session, setSession] = React.useState(1);
  const [distractions, setDistractions] = React.useState(0);
  const [showDistract, setShowDistract] = React.useState(false);
  const task = { title: 'Review quarterly report', tag: 'work' };
  const TOTAL = 25 * 60;

  React.useEffect(() => {
    if (!running) return;
    const id = setInterval(() => {
      setSeconds(s => {
        if (s <= 1) { setRunning(false); return 0; }
        return s - 1;
      });
    }, 1000);
    return () => clearInterval(id);
  }, [running]);

  const fmt = (s) => `${String(Math.floor(s / 60)).padStart(2, '0')}:${String(s % 60).padStart(2, '0')}`;
  const progress = (TOTAL - seconds) / TOTAL;
  const r = 88;
  const circ = 2 * Math.PI * r;

  const handleComplete = () => { setRunning(false); setSeconds(25 * 60); setSession(s => s + 1); };
  const handleDistraction = () => { setDistractions(d => d + 1); setShowDistract(false); };

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#1e1b4b] via-[#312e81] to-[#4c1d95] max-w-[390px] mx-auto flex flex-col items-center px-6 pt-8 pb-8 font-sans">
      {/* Session info */}
      <div className="self-stretch flex justify-between items-center mb-8">
        <div className="text-white/60 text-sm font-semibold">Session #{session}</div>
        <div className="flex gap-1">
          {Array.from({ length: 4 }).map((_, i) => (
            <div key={i} className={`w-6 h-2 rounded-full ${i < session ? 'bg-violet-400' : 'bg-white/15'}`} />
          ))}
        </div>
      </div>

      {/* Task chip */}
      <div className="bg-white/10 rounded-full px-5 py-2 mb-9 flex items-center gap-2">
        <span className="text-sm">🎯</span>
        <span className="text-indigo-100 text-sm font-medium max-w-[200px] overflow-hidden text-ellipsis whitespace-nowrap">{task.title}</span>
      </div>

      {/* Timer Ring */}
      <div className="relative w-[220px] h-[220px] mb-9">
        <svg width={220} height={220} className="-rotate-90">
          <circle cx={110} cy={110} r={r} fill="none" stroke="rgba(255,255,255,0.1)" strokeWidth={12} />
          <circle cx={110} cy={110} r={r} fill="none" stroke="url(#grad)" strokeWidth={12}
            strokeDasharray={circ} strokeDashoffset={circ * (1 - progress)} strokeLinecap="round"
            style={{ transition: 'stroke-dashoffset 1s linear' }} />
          <defs>
            <linearGradient id="grad" x1="0%" y1="0%" x2="100%" y2="0%">
              <stop offset="0%" stopColor="#818cf8" />
              <stop offset="100%" stopColor="#c084fc" />
            </linearGradient>
          </defs>
        </svg>
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <div className="text-[42px] font-extrabold text-white tracking-tight">{fmt(seconds)}</div>
          <div className="text-[13px] text-white/50 mt-1">{running ? 'focusing...' : seconds === 0 ? 'session done! 🎉' : 'ready'}</div>
        </div>
      </div>

      {/* Controls */}
      <div className="flex gap-4 mb-7">
        <button onClick={() => { setSeconds(25 * 60); setRunning(false); }}
          className="w-[52px] h-[52px] rounded-full bg-white/10 border-none text-white text-[22px] cursor-pointer">⏹</button>
        <button onClick={() => setRunning(r => !r)}
          className={`w-[72px] h-[72px] rounded-full border-none text-white text-[30px] cursor-pointer shadow-lg transition-all duration-200 ${running ? 'bg-red-500' : 'bg-gradient-to-br from-indigo-400 to-purple-400'}`}>
          {running ? '⏸' : '▶'}
        </button>
        <button onClick={handleComplete} disabled={!running}
          className={`w-[52px] h-[52px] rounded-full border-none text-[22px] ${running ? 'bg-emerald-500/30 text-emerald-300 cursor-pointer' : 'bg-white/5 text-white/20 cursor-not-allowed'}`}>✓</button>
      </div>

      {/* Stats */}
      <div className="self-stretch bg-white/[0.07] rounded-[20px] p-4 grid grid-cols-3 gap-1 mb-4">
        {[
          { label: 'Sessions', value: session },
          { label: 'Focus Time', value: `${(session - 1) * 25}m` },
          { label: 'Distractions', value: distractions },
        ].map(s => (
          <div key={s.label} className="text-center">
            <div className="text-xl font-extrabold text-indigo-100">{s.value}</div>
            <div className="text-[11px] text-white/40 mt-0.5">{s.label}</div>
          </div>
        ))}
      </div>

      <button onClick={() => setShowDistract(true)}
        className="bg-white/[0.07] border border-white/10 rounded-xl px-5 py-[10px] text-white/50 text-[13px] cursor-pointer">
        📵 Log distraction
      </button>

      {/* Distraction modal */}
      {showDistract && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-6">
          <div className="bg-[#1e1b4b] rounded-[20px] p-7 w-full max-w-[340px] text-center">
            <div className="text-[36px] mb-3">📵</div>
            <div className="text-lg font-bold text-indigo-100 mb-2">Distracted?</div>
            <div className="text-sm text-white/50 mb-6">That's okay. Log it and refocus.</div>
            <div className="flex gap-[10px]">
              <button onClick={() => setShowDistract(false)} className="flex-1 bg-white/[0.07] border-none rounded-xl p-[13px] text-white/50 cursor-pointer text-sm">Cancel</button>
              <button onClick={handleDistraction} className="flex-1 bg-gradient-to-br from-indigo-400 to-purple-400 border-none rounded-xl p-[13px] text-white cursor-pointer text-sm font-bold">Refocus 💪</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
